import React from "react"
import { Link, graphql } from "gatsby"
import _ from "lodash"
import Layout from "../components/layout"
import SEO from "../components/seo"
import Typed from "typed.js"
// import axios from "axios"

class BlogIndex extends React.Component {
  componentDidMount() {
    // axios.get('https://c.winteraq.com/dailies?_sort=cts:DESC&_limit=1').then(({data})=>{
    //   this.didTyped(data[0]);
    // }).catch(err=>{
    //   this.didTyped({
    //     content:'The greatest thing you\'ll ever learn is just to love and be loved in return.',
    //     translation:'你会明白，人生中最美好的事，莫过于爱的同时也被爱。',
    //     from:'Nat King Cole, "Nature Boy"'
    //   })
    // });
    this.didTyped({
      content:
        "The greatest thing you'll ever learn is just to love and be loved in return.",
      translation: "你会明白，人生中最美好的事，莫过于爱的同时也被爱。",
      from: 'Nat King Cole, "Nature Boy"',
    })
  }

  didTyped(data) {
    let str = `${data.content}
${data.translation}
--- `
    let options = {
      strings: [
        str + "Who??^1000",
        str + "It's me ^3000",
        str + "Haha, make a joke",
        str + data.from,
      ],
      typeSpeed: 20,
      startDelay: 300,
      // loop: true,
    }
    new Typed(".description .typed", options)
  }

  render() {
    const { data } = this.props
    const siteTitle = data.site.siteMetadata.title
    const posts = data.allMarkdownRemark.edges
    const groupPost = _.groupBy(posts, (p) => p.node.frontmatter.year)
    const groupPostKeys = _.orderBy(
      Object.keys(groupPost),
      (o) => Number(o.year),
      ["desc"]
    )
    return (
      <Layout location={this.props.location} title={siteTitle}>
        <SEO
          title="All posts"
          keywords={[`blog`, `gatsby`, `javascript`, `react`]}
        />
        <section id="about">
          <div className="description coding">
            <span className="typed prompt" />
          </div>
        </section>
        {groupPostKeys.map((year) => {
          return (
            <div className="y-blog" key={year}>
              <h2>{year}</h2>
              {groupPost[year].map(({ node }) => {
                const title = node.frontmatter.title || node.fields.slug
                return (
                  <div className="post-item" key={node.fields.slug}>
                    <h3
                      style={
                        {
                          // marginBottom: rhythm(1 / 4),
                        }
                      }
                    >
                      <Link
                        style={{ boxShadow: `none`, color: "#2bbc8a" }}
                        to={node.fields.slug}
                      >
                        {title}
                      </Link>
                    </h3>
                    <small>{node.frontmatter.date}</small>
                    <p
                      dangerouslySetInnerHTML={{
                        __html: node.frontmatter.description || node.excerpt,
                      }}
                    />
                  </div>
                )
              })}
            </div>
          )
        })}
      </Layout>
    )
  }
}

export default BlogIndex

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(
      sort: { fields: [frontmatter___date], order: DESC }
      filter: { frontmatter: { published: { ne: false } } }
    ) {
      edges {
        node {
          excerpt
          fields {
            slug
          }
          frontmatter {
            date(formatString: "MMMM DD, YYYY")
            year: date(formatString: "YYYY")
            title
            description
          }
        }
      }
    }
  }
`
